VALUES
  ('aviation-8b306344-moex-00080', 'aviation-8b306344', 'aviation-8b306344-moex-112-7bf35b0f', 'sub-aviation-8b306344-06', NULL, 'single_choice', '依刑事訴訟法第93條第2項規定，犯罪嫌疑人遭逮捕後，檢察官認為有羈押之必要，應自逮捕時起24 小時內聲請法院羈押。關於本項規定，下列敘述何者正確？', '["本項規定之內容為絕對法律保留事項，立法者得在符合比例原則之範圍內，將24小時修正為48小時", "本項規定之內容為相對法律保留事項，立法者得授權檢察官在必要時，將24小時延長為48小時", "本項規定之內容為憲法保留事項，立法者不得將24小時修正為48小時", "本項規定之內容為行政保留事項，檢察官得在必要時，將24小時延長為48小時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:06+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航管制"}'::jsonb, NULL),
  ('aviation-8b306344-moex-00081', 'aviation-8b306344', 'aviation-8b306344-moex-112-7bf35b0f', 'sub-aviation-8b306344-06', NULL, 'single_choice', '集會自由應屬表現自由之範疇，依司法院大法官解釋意旨，關於集會自由，下列敘述何者錯誤？', '["集會遊行法對於不遵從解散及制止命令之首謀者科以刑責，將造成寒蟬效應，有違憲法對集會自由 之保障", "國家應提供適當集會場所，採取有效保護集會之安全措施，使參與集會遊行者在毫無恐懼情況下行 使集會自由", "關於集會遊行時間、地點及方式等限制，因無涉集會遊行之目的或內容，屬於立法自由形成範圍", "集會遊行法之事前許可制未排除緊急性及偶發性集會，已違反比例原則之要求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:06+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航管制"}'::jsonb, NULL),
  ('aviation-8b306344-moex-00082', 'aviation-8b306344', 'aviation-8b306344-moex-112-7bf35b0f', 'sub-aviation-8b306344-06', NULL, 'single_choice', '內政部依據社會團體許可立案作業規定，不准中國比較法學會變更名稱為臺灣法學會，依司法院大法 官解釋之意旨，侵害人民受憲法保障的何種權利？', '["講學自由", "結社自由", "人格權", "集會自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:06+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航管制"}'::jsonb, NULL),
  ('aviation-8b306344-moex-00083', 'aviation-8b306344', 'aviation-8b306344-moex-112-7bf35b0f', 'sub-aviation-8b306344-06', NULL, 'single_choice', '依司法院大法官解釋，關於憲法平等權之司法違憲審查，下列何者不會影響審查密度之寬嚴？', '["分類標準是否涉及憲法基本國策之國家積極義務", "差別待遇是否涉及重要基本權利", "分類標準是否涉及政治上之弱勢群體", "差別待遇屬於直接或間接歧視"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:06+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航管制"}'::jsonb, NULL),
  ('aviation-8b306344-moex-00084', 'aviation-8b306344', 'aviation-8b306344-moex-112-7bf35b0f', 'sub-aviation-8b306344-06', NULL, 'single_choice', '依司法院大法官解釋，舊企業併購法未使因以現金作為對價之合併而喪失股權之股東，及時獲取合併 對公司利弊影響之資訊，亦未就股份對價公平性之確保，設置有效之權利救濟機制，係侵害公司股東 下列何種憲法權利？', '["財產權", "工作權", "集會自由", "結社自由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:06+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航管制"}'::jsonb, NULL),
  ('aviation-8b306344-moex-00085', 'aviation-8b306344', 'aviation-8b306344-moex-112-7bf35b0f', 'sub-aviation-8b306344-06', NULL, 'single_choice', '社會救助法第4條所定最低生活費標準，乃為貫徹憲法所保障之何種基本權利？', '["平等權", "生存權", "工作權", "財產權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:06+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航管制"}'::jsonb, NULL),
  ('aviation-8b306344-moex-00086', 'aviation-8b306344', 'aviation-8b306344-moex-112-7bf35b0f', 'sub-aviation-8b306344-06', NULL, 'single_choice', '我國憲法第129條明定，憲法所規定之各種選舉，以普通、平等、直接及無記名投票之方法行之。有 關選舉原則，下列敘述何者錯誤？', '["縣市議會議長及副議長之選舉及罷免，自應受本條拘束", "憲法明文規定婦女保障名額制度，仍無違平等原則之要求", "公職人員選舉罷免法處罰選舉人之亮票行為，是為貫徹秘密投票原則", "中華民國國民年滿20歲者有依法選舉之權，是普通原則的具體展現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:06+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航管制"}'::jsonb, NULL),
  ('aviation-8b306344-moex-00087', 'aviation-8b306344', 'aviation-8b306344-moex-112-7bf35b0f', 'sub-aviation-8b306344-06', NULL, 'single_choice', '公務人員週休二日實施辦法第4條第1項規定：「交通運輸、警察、消防、海岸巡防、醫療、關務等機 關（構），為全年無休服務民眾，應實施輪班、輪休制度。」可能對下列何種基本權利構成侵害？', '["訴訟權", "健康權", "人身自由權", "應考試權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:06+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航管制"}'::jsonb, NULL),
  ('aviation-8b306344-moex-00088', 'aviation-8b306344', 'aviation-8b306344-moex-112-7bf35b0f', 'sub-aviation-8b306344-06', NULL, 'single_choice', '依司法院釋字第791號解釋，下列敘述何者錯誤？', '["以刑罰制裁通姦及相姦行為，其目的在於約束配偶雙方履行婚姻忠誠義務，以維護婚姻制度及個別 婚姻之存續，洵屬正當", "有配偶而與人通姦者，處1年以下有期徒刑之規定，涉及憲法第22條保障之性自主權", "刑法通姦罪規定對性自主權之限制是否合於比例原則，應受較嚴格之審查", "對配偶撤回通姦罪告訴，其效力不及於相姦人之規定，與憲法第7條平等權之意旨並無違背"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:06+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航管制"}'::jsonb, NULL),
  ('aviation-8b306344-moex-00089', 'aviation-8b306344', 'aviation-8b306344-moex-112-7bf35b0f', 'sub-aviation-8b306344-06', NULL, 'single_choice', '依司法院大法官解釋之意旨，下列何者屬於對人民職業選擇自由之主觀限制？', '["非視障者不得從事按摩業", "藥師僅得於單一處所執業", "具有博士學位者始得擔任助理教授", "限制同一區域內有線電視系統業者之經營總數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:06+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航管制"}'::jsonb, NULL)
